import { Component } from '@angular/core';
import { Validators } from '@angular/forms';
import { FormControl } from '@angular/forms';
import { FormGroup } from '@angular/forms';
import { finalize } from 'rxjs';
import { UserLogin } from './login.interface';
import { Router } from '@angular/router';
import { UtilityService } from '../Utility.Service';
import { HttpService } from '../http.service';


@Component({
  selector: 'app-login',
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.scss', '../signup/signup.component.scss']
})
export class LoginComponent {
  errorMessage?: string;

  loginForm = new FormGroup({
      userName: new FormControl('', [
          Validators.required,
          Validators.minLength(2),
          Validators.maxLength(12),
      ]),
      password: new FormControl('', [
          Validators.required,
          Validators.minLength(2),
          Validators.maxLength(20),
      ]),
    });

    login() {
      this.errorMessage = '';

      const sub = this.http.post<UserLogin>('login', this.loginForm.value).pipe(finalize(() => {
          if (sub?.unsubscribe) {
              sub.unsubscribe();
          }
      })).subscribe(data => {
          if (data.status == 'error') {
              this.errorMessage = data.message;
          } else {
              this.utility.setUser(data.user);
              this.router.navigate(['home']);
          }
      });
  }


  constructor(private http: HttpService, private utility: UtilityService, private router: Router) { }

  ngOnInit() {
    if (this.utility.getUser()) {
        this.router.navigate(['']);
    }
  }
  }



<h1>         hhי</h1>


<h1>התחברות</h1>

<form [formGroup]="loginForm">
    <div class="field">
        <label><i class="fa fa-user"></i> שם משתמש:</label>
        <input class="w3-input w3-border w3-round" type="text" formControlName="userName">
    </div>

    <div class="field">
        <label><i class="fa fa-asterisk"></i> סיסמה:</label>
        <input class="w3-input w3-border w3-round" type="password" formControlName="password">
    </div>

    <div *ngIf="errorMessage" class="w3-container w3-red">{{ errorMessage }}</div>

    <button class="w3-btn w3-green w3-round w3-block" [disabled]="!loginForm.valid" (click)="login()">התחברות <i class="fa fa-check"></i></button>

    <p>
        <a routerLink="/signup">ליצירת חשבון חדש</a>
    </p>

</form>
